insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('66857', 'ra.ja', 'raja', '', '', '["Nomina","Nomina","Nomina","Nomina","Nomina","Nomina","Nomina","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"penguasa tertinggi pada suatu kerajaan (biasanya diperoleh sebagai warisan); orang yang mengepalai dan memerintah suatu bangsa atau negara","contoh":[{"nomor":2,"teks":"negara kerajaan diperintah oleh seorang --"}]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"kepala daerah istimewa; kepala suku; sultan","contoh":[]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"sebutan untuk penguasa tertinggi dari suatu kerajaan","contoh":[]},{"nomor":"4","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"orang yang besar kekuasaannya (pengaruhnya) dalam suatu lingkungan (perusahaan)","contoh":[{"nomor":2,"teks":"-- minyak"}]},{"nomor":"5","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"orang yang mempunyai keistimewaan khusus (seperti sifat, kepandaian, kelicikan)","contoh":[{"nomor":2,"teks":"-- kumis"},{"nomor":4,"teks":"-- copet"}]},{"nomor":"6","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"binatang (jin dan sebagainya) yang dianggap berkuasa terhadap sesamanya","contoh":[{"nomor":2,"teks":"-- buaya"},{"nomor":4,"teks":"-- jin"}]},{"nomor":"7","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"buah catur yang terpenting","contoh":[]},{"nomor":"8","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"kartu (truf) yang bergambar raja","contoh":[]}]', null, '["beraja","beraja-raja","berkerajaan","kerajaan","meraja","merajai","merajakan"]', '["raja adat","raja alam","raja babandiang","raja bodoh","raja brana","raja buah","raja diraja","raja hutan","raja jalanan","raja jenang","raja laut","raja minyak","raja muda","raja rimba","raja sehari","raja siang","raja tega","raja udang","Raja Uti"]', '["ayam itik raja pada tempatnya","kerja raja dijunjung, kerja kita dikelek","malang celaka Raja Genggang, anak terbeli tunjang hilang","nafsu nafsi, raja di mata, sultan di hati","raja adil raja disembah, raja lalim raja disanggah","raja negeri raja pasak, raja adat raja agama","sayang anak badak tampung, cucu konon badak raja","siapa pun jadi raja, tanganku ke dahi juga","tiada raja menolak sembah","tohok raja tidak dapat dielakkan"]', '[]', '[{"peribahasa":"ayam itik raja pada tempatnya","makna":"Setiap orang berkuasa di lingkungannya masing-masing."},{"peribahasa":"kerja raja dijunjung, kerja kita dikelek","makna":"Mementingkan pekerjaan orang lain daripada pekerjaan sendiri."},{"peribahasa":"malang celaka Raja Genggang, anak terbeli tunjang hilang","makna":"Mengalami kemalangan yang bertubi-tubi."},{"peribahasa":"nafsu nafsi, raja di mata, sultan di hati","makna":"Berbuat sesuka hati; menuruti hawa nafsu."},{"peribahasa":"raja adil raja disembah, raja lalim raja disanggah","makna":"Pemimpin yang adil akan dihormati, sedangkan pemimpin yang zalim akan dilawan."},{"peribahasa":"raja negeri raja pasak, raja adat raja agama","makna":"Raja adalah pemimpin negara, sedangkan adat dan agama adalah pedoman hidup."},{"peribahasa":"sayang anak badak tampung, cucu konon badak raja","makna":"Kasih sayang yang tidak pada tempatnya."},{"peribahasa":"siapa pun jadi raja, tanganku ke dahi juga","makna":"Tidak peduli siapa yang berkuasa, rakyat jelata tetap dalam keadaan yang sama."},{"peribahasa":"tiada raja menolak sembah","makna":"Orang yang suka dipuji atau dihormati."},{"peribahasa":"tohok raja tidak dapat dielakkan","makna":"Perintah atau kehendak orang yang berkuasa tidak dapat ditolak."}]');
