insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('69211', 're.ze.ki', 'rezeki', '', '', '["Nomina","Nomina","kiasan"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"Segala sesuatu yang digunakan untuk memelihara kelangsungan hidup, yang diyakini sebagai pemberian Tuhan; dapat berupa makanan sehari-hari, kebutuhan pokok, maupun nafkah.","contoh":[{"nomor":1,"teks":"Setiap makhluk telah ditentukan rezekinya oleh Tuhan."},{"nomor":2,"teks":"Pekerjaan itu menjadi sumber rezeki bagi keluarganya."},{"nomor":3,"teks":"Ia selalu bersyukur atas rezeki yang diterima hari ini."}]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"ki","nama":"kiasan","tipe":"kelas_kata"}],"definisi":"Segala bentuk penghidupan, pendapatan, keuntungan, atau kesempatan yang memungkinkan seseorang memperoleh kebutuhan hidup, baik secara materi maupun nonmateri.","contoh":[{"nomor":1,"teks":"Bekerja di luar negeri membuka pintu rezeki yang lebih luas baginya."},{"nomor":2,"teks":"Kesempatan menjadi pembicara di konferensi adalah rezeki yang tidak disangka-sangka."},{"nomor":3,"teks":"Keberhasilan usahanya membawa rezeki berlimpah bagi seluruh karyawan."}]}]', '{"text":"[Arab رِزْقٌ rizq n sg m ''segala sesuatu yang dipakai untuk memelihara kehidupan (yang diberikan oleh Tuhan)'']","languages":["Arab"]}', '["berezeki"]', '["rezeki ayam","rezeki batin","rezeki halal","rezeki kaget","rezeki mahal","rezeki mata","rezeki meninggi","rezeki merendah","rezeki murah","rezeki musang","rezeki nomplok"]', '["ada nyawa (umur), ada rezeki","mara jangan dipukat, rezeki jangan ditolak","rezeki dipatuk ayam","rezeki elang tak akan dapat (dimakan) oleh musang (burung pipit)"]', '["ada nyawa, ada rezeki","banyak anak, banyak rezeki"]', '[{"peribahasa":"ada nyawa (umur), ada rezeki","makna":"Selama seseorang masih hidup, ia masih memiliki kesempatan untuk memperoleh penghidupan."},{"peribahasa":"mara jangan dipukat, rezeki jangan ditolak","makna":"Kesempatan yang baik hendaknya dimanfaatkan dan tidak disia-siakan."},{"peribahasa":"rezeki dipatuk ayam","makna":"Kesempatan atau keuntungan yang sudah di depan mata hilang karena kelalaian."},{"peribahasa":"rezeki elang tak akan dapat (dimakan) oleh musang (burung pipit)","makna":"Rezeki atau keuntungan yang sudah ditentukan untuk seseorang tidak akan berpindah kepada orang lain."}]');
